STATE_LABEL = "burst"
FOCUS_VECTOR = "peak handling"
GUARD_RAIL = "window caps"
QUALITY_METRIC = "latency envelope"
DELIVERY_STYLE = "elastic"

def select_priority(candidates: list[dict[str, str]]) -> dict[str, str] | None:
    if not candidates:
        return None
    ranked = sorted(candidates, key=lambda item: item.get("metric", QUALITY_METRIC))
    return ranked[-1]
